import{_ as e,o as t,c as l,a2 as r}from"./chunks/framework.Crpw6aS5.js";const _=JSON.parse('{"title":"1985年巴菲特致股东的信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1985年/核心总结.md","filePath":"01_letters/1985年/核心总结.md"}'),o={name:"01_letters/1985年/核心总结.md"};function i(n,a,s,h,d,u){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="_1985年巴菲特致股东的信核心总结" tabindex="-1">1985年巴菲特致股东的信核心总结 <a class="header-anchor" href="#_1985年巴菲特致股东的信核心总结" aria-label="Permalink to &quot;1985年巴菲特致股东的信核心总结&quot;">​</a></h1><h2 id="简要导读" tabindex="-1">简要导读 <a class="header-anchor" href="#简要导读" aria-label="Permalink to &quot;简要导读&quot;">​</a></h2><p>1985年巴菲特终于关闭了持续二十年的纺织业务，他坦诚复盘了自己坚持这么久的错误，把最核心的投资道理讲得清清楚楚：&quot;当一艘船一直在漏水，换船比补洞更值得&quot;。这封信还把巴菲特对股权激励的批判、对保险行业新格局的判断讲得十分透彻，非常值得读。文末可下载英文原版PDF。</p><h2 id="一、最终关掉纺织业务-承认错误-接受教训" tabindex="-1">一、最终关掉纺织业务：承认错误，接受教训 <a class="header-anchor" href="#一、最终关掉纺织业务-承认错误-接受教训" aria-label="Permalink to &quot;一、最终关掉纺织业务：承认错误，接受教训&quot;">​</a></h2><p>巴菲特坚持了二十年，最终还是关了纺织业务，他坦诚自己错了：</p><ul><li>一开始我觉得，只要管理层努力，还是能把烂生意做好，结果证明，商业模式错了，再努力也没用。&quot;好经理在烂生意上，就像好司机开好车，但是烂路怎么开都快不了&quot;。</li><li>你不断投资进去，每个人单独看投资决策都对，每个人都觉得我投资一块钱就能降成本，结果所有投资人都这么干，整体价格还是下来了，最后大家一起赚不到钱，所有人投资都打水漂。</li><li>给投资者的教训：很多重资产大宗商品行业，全球产能过剩，你再努力也没用，不如早点关掉。&quot;我早就该懂，结果一直坚持，错在我自己&quot;。</li><li>最后卖掉设备，原来1300万买的，卖废品才卖了16万，你看，通胀时代，重资产不值钱，有形多不代表价值高，反而优秀轻资产好生意，通胀下价值涨得飞快。</li></ul><h2 id="二、股权激励到底对不对-巴菲特说透了" tabindex="-1">二、股权激励到底对不对，巴菲特说透了 <a class="header-anchor" href="#二、股权激励到底对不对-巴菲特说透了" aria-label="Permalink to &quot;二、股权激励到底对不对，巴菲特说透了&quot;">​</a></h2><p>巴菲特说，现在公司固定价格股权激励太不公平：</p><ul><li>公司留存盈利自动涨价值，经理什么都不用干，拿着固定价格期权就能赚钱，就是免费拿原有股东的价值，因为留存盈利本来就是股东的，不是经理给股东赚的。</li><li>你存银行，利息不拿出来再存，十年后利息也会翻倍，这不等于经理能干，这是复利自然增长。现在很多经理就是拿这个当自己功劳，拿期权赚大钱，对股东不公平。</li><li>巴菲特给了三个正确原则： <ol><li>期权应该和公司整体业绩绑定，只有对公司整体负责的经理才能拿，局部经理不能拿整体奖励。</li><li>期权价格要合理定价，要反映资金成本和留存收益，不能随便给内部人低价。</li><li>很多优秀公司本来就对期权制度运作很好，没坏就不要改。</li></ol></li></ul><p>伯克希尔自己激励体系，就是每个业务单元干得好拿得多，不看伯克希尔股价，只看你自己业务结果，对就是对，错就是错，结果说话，所以很公平。</p><h2 id="三、保险行业新格局-我们的机会终于来了" tabindex="-1">三、保险行业新格局：我们的机会终于来了 <a class="header-anchor" href="#三、保险行业新格局-我们的机会终于来了" aria-label="Permalink to &quot;三、保险行业新格局：我们的机会终于来了&quot;">​</a></h2><p>过去这些年，很多再保险公司吃了大亏，很多大额风险不敢接了，原来都是发行人赚大头，再保险背风险，现在再保险缩容量，发行人自己也接不住，所以我们来了：我们资本够强，愿意直接接大单，自己承担大头，不需要分出去给再保险，所以现在很多大单都来找我们，这是我们的大机会。</p><p>巴菲特结论：保险行业现在是产能紧了，1985年保费增长20.9%，综合成本率118%，依然很差，但短期变好，长期还是不行，因为只要赚钱，大家就会增资扩产能，很快又会产能过剩价格战，我们就是趁现在接大单，赚一笔是一笔，我们资本强，能熬。</p><h2 id="四、华盛顿邮报投资案例-一次教科书级别的投资" tabindex="-1">四、华盛顿邮报投资案例：一次教科书级别的投资 <a class="header-anchor" href="#四、华盛顿邮报投资案例-一次教科书级别的投资" aria-label="Permalink to &quot;四、华盛顿邮报投资案例：一次教科书级别的投资&quot;">​</a></h2><p>巴菲特说，1973年我们买华盛顿邮报，整个市场价值才1亿美元，我们算出来内在价值就值4-5亿，当时所有机构都不买，因为有效市场理论说，市场永远对，所以这么便宜肯定错了，结果我们买了，现在我们持股市值2.21亿，成本才1,060万，赚了20多倍，这就是格雷厄姆理论的胜利。</p><p>整个过程，凯瑟琳·格雷厄姆太伟大了，她知道股价低估，大力回购股票，放大了每股内在价值，最终市场终于认了，估值修复，我们赚了三倍钱，一半是企业增长，一半是回购加估值修复。现在华盛顿邮报已经涨到18亿市值，潜在收益肯定不如以前了，这就是市场变化，现在整体市场都不便宜了，我们也接受。</p><h2 id="五、核心启示" tabindex="-1">五、核心启示 <a class="header-anchor" href="#五、核心启示" aria-label="Permalink to &quot;五、核心启示&quot;">​</a></h2><ol><li><strong>承认错误要趁早</strong>：烂生意就是烂生意，再努力也没用，该关就关，不要舍不得沉没成本，巴菲特坚持了二十年才关，自己认错，这个教训太值钱了。</li><li><strong>股权激励不对等，吃股东</strong>：固定价格股权激励天然不对，因为留存盈利自动涨价值，经理不干活也赚，这个点巴菲特讲透了，很多公司现在还在这么玩，股东要小心。</li><li><strong>行业好机会来自别人怕了</strong>：保险行业亏了很多年，很多人不敢玩了，资本够强的就能拿到好生意，这就是逆向投资。</li></ol><hr><blockquote><p>📎 <strong>文末小惊喜</strong>：可点击下载<a href="Chairman&#39;s%20Letter%20-%201985.pdf">巴菲特1985年股东信原件PDF</a>，原汁原味阅读英文原文。</p></blockquote>',20)])])}const c=e(o,[["render",i]]);export{_ as __pageData,c as default};
